### 3. View Component (view.tsx - simplified)

```typescript
const PointsView: FC<PointsViewProps> = ({
  isLoadingBalance,
  handleGoBack,
  pointsAvailable,
  items,
  onOpenExtract,
  onOpenDefault,
  modalizeRef,
  isMyOrders,
  setIsMyOrders,
  onMenuPress,
  handleMyOrders,
}) => {
  return (
    <>
      <BasicScreen
        errorButtonOnPress={() => {}}
        hasScroll
        leftIconOnPress={() => {
          isMyOrders ? setIsMyOrders(false) : handleGoBack();
        }}
        rightIcon="icon-menu"
        rightIconOnPress={onMenuPress}
        hasRightIcon={!isMyOrders}
        title={isMyOrders ? 'Meu espaço' : 'Programa de Pontos'}
      >
        {isMyOrders ? (
          <CardActivity
            isLoading={isLoadingBalance}
            icon="icon-shopping-bag"
            showIcon
            showIconRight={false}
            hideBackground
