      order: 3,
      questions: [
        { question: 'Pontos expiram?', answer: 'Sim, após 12 meses.' },
      ],
    },
  },
];

function seedStore(points: number) {
  const state = useRootStore.getState() as any;
  if (state.pointsBalanceActions) {
    state.pointsBalanceActions.setPoints(points);
  }
  if (state.parameterPointsProgramActions) {
    state.parameterPointsProgramActions.setData(MOCK_LEARN_MORE_DATA);
    state.parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.SUCCESS);
  }
}

function PointsStoryWrapper({ points = 15320, isLoading = false }: { points?: number; isLoading?: boolean }) {
  const [isMyOrders, setIsMyOrders] = useState(false);
  const modalizeRef = useRef(null as any);

  useEffect(() => {
    seedStore(points);
  }, [points]);

  return (
    <PointsView
      isLoadingBalance={isLoading}
      handleGoBack={() => {}}
      pointsAvailable={points}
      items={MOCK_ITEMS}
      onOpenExtract={() => {}}
      onOpenDefault={() => {}}
      modalizeRef={modalizeRef}
      isMyOrders={isMyOrders}
      setIsMyOrders={setIsMyOrders}
      handlerGoHome={() => {}}
      onMenuPress={() => setIsMyOrders(true)}
      handleMyOrders={() => {}}
    />
  );
}

const meta: Meta<typeof PointsStoryWrapper> = {
  title: 'Screens/Points',
  component: PointsStoryWrapper,
  decorators: [NavigationDecorator],
};

export default meta;
type Story = StoryObj<typeof PointsStoryWrapper>;

export const Loaded: Story = {
  name: 'Loaded (15.320 pts)',
  args: { points: 15320, isLoading: false },
};

export const ZeroPoints: Story = {
  name: 'Zero Points',
  args: { points: 0, isLoading: false },
};

export const Loading: Story = {
  name: 'Loading State',
  args: { points: 0, isLoading: true },
};

